20	fn ensure_fixture_dir() -> Result<String, StepResult> {
21	    FIXTURE_DIR.with(|dir| {
22	        let mut borrow = dir.borrow_mut();
23	        if borrow.is_none() {
24	            match tempfile::TempDir::new() {
25	                Ok(td) => {
26	                    let path = td.path().to_string_lossy().to_string();
27	                    *borrow = Some(td);
