29	                }
30	                Err(e) => {
31	                    return Err(StepResult::fail(format!("failed to create temp dir: {}", e)));
32	                }
33	            }
34	        }
35	        Ok(FIXTURE_ROOT.with(|r| r.borrow().clone().unwrap()))
36	    })
