40	    let full = Path::new(root).join(relative);
41	    if let Some(parent) = full.parent() {
42	        std::fs::create_dir_all(parent)
43	            .map_err(|e| StepResult::fail(format!("mkdir {}: {}", parent.display(), e)))?;
44	    }
45	    std::fs::write(&full, content)
46	        .map_err(|e| StepResult::fail(format!("write {}: {}", full.display(), e)))?;
